import{_ as a,o as t,c as o,a2 as s}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"MCP / SSH / WebDAV","description":"","frontmatter":{},"headers":[],"relativePath":"features/mcp-ssh-webdav.md","filePath":"features/mcp-ssh-webdav.md"}'),r={name:"features/mcp-ssh-webdav.md"};function i(n,e,l,c,d,u){return t(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="mcp-ssh-webdav" tabindex="-1">MCP / SSH / WebDAV <a class="header-anchor" href="#mcp-ssh-webdav" aria-label="Permalink to &quot;MCP / SSH / WebDAV&quot;">​</a></h1><p>Lyra Code integrates remote services through three powerful protocols. All connections are managed through a unified natural-language configuration interface.</p><h2 id="mcp-model-context-protocol" tabindex="-1">MCP (Model Context Protocol) <a class="header-anchor" href="#mcp-model-context-protocol" aria-label="Permalink to &quot;MCP (Model Context Protocol)&quot;">​</a></h2><p>Connect to remote MCP servers to extend the Agent&#39;s capabilities:</p><ul><li><strong>Streamable HTTP</strong> transport</li><li><strong>SSE (Server-Sent Events)</strong> transport</li><li>Add, configure, enable, and disable servers on the fly</li><li>Each MCP tool is prefixed with <code>mcp_</code> for clear identification</li></ul><h3 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h3><ul><li>Connect to specialized AI tools and data sources</li><li>Integrate with external APIs through MCP wrappers</li><li>Extend Lyra Code&#39;s native capabilities without modifying the app</li></ul><div class="tip custom-block"><p class="custom-block-title">MCP Tools</p><p>Tools from MCP servers appear alongside native tools. All MCP tool calls require <strong>user confirmation</strong> before execution.</p></div><h2 id="ssh" tabindex="-1">SSH <a class="header-anchor" href="#ssh" aria-label="Permalink to &quot;SSH&quot;">​</a></h2><p>Securely connect to remote servers for administration and automation:</p><h3 id="supported-targets" tabindex="-1">Supported Targets <a class="header-anchor" href="#supported-targets" aria-label="Permalink to &quot;Supported Targets&quot;">​</a></h3><ul><li><strong>Linux</strong> servers</li><li><strong>Windows</strong> servers</li><li><strong>Git</strong> servers</li></ul><h3 id="authentication-methods" tabindex="-1">Authentication Methods <a class="header-anchor" href="#authentication-methods" aria-label="Permalink to &quot;Authentication Methods&quot;">​</a></h3><ul><li>Password-based login</li><li>Private key authentication (with optional passphrase)</li></ul><h3 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h3><ul><li>Execute commands remotely and receive <code>stdout</code>/<code>stderr</code></li><li>Configurable working directory per session</li><li>Input lines for interactive commands (Y/N prompts etc.)</li><li>Timeout control</li></ul><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li>Every SSH command requires <strong>explicit user approval</strong></li><li>Full command preview before execution</li><li>Use <code>list_ssh_servers</code> to view configured connections</li><li>Always check system resources before installing or modifying software</li></ul><h2 id="webdav" tabindex="-1">WebDAV <a class="header-anchor" href="#webdav" aria-label="Permalink to &quot;WebDAV&quot;">​</a></h2><p>Access and manage remote storage through WebDAV:</p><h3 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operation</th><th>Description</th></tr></thead><tbody><tr><td><code>webdav_list</code></td><td>Browse directories with PROPFIND</td></tr><tr><td><code>webdav_search</code></td><td>Search files by name or path</td></tr><tr><td><code>webdav_download</code></td><td>Download files to workspace</td></tr><tr><td><code>webdav_upload</code></td><td>Upload workspace files to server</td></tr></tbody></table><h3 id="cloud-backup" tabindex="-1">Cloud Backup <a class="header-anchor" href="#cloud-backup" aria-label="Permalink to &quot;Cloud Backup&quot;">​</a></h3><ul><li>Export backups directly to WebDAV</li><li>Default path: <code>/LyraCode/lyra_backup_latest.zip</code></li><li>Automatic latest-backup detection for imports</li><li>Full and selective backup options (profiles, conversations, configs, secrets)</li></ul><h2 id="natural-language-config-management" tabindex="-1">Natural-Language Config Management <a class="header-anchor" href="#natural-language-config-management" aria-label="Permalink to &quot;Natural-Language Config Management&quot;">​</a></h2><p>All MCP, SSH, WebDAV, Skills, and Agent tool configurations can be managed through natural language:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Add an MCP server at https://my-mcp.example.com with Streamable HTTP transport&quot;</span></span>
<span class="line"><span>&quot;Configure SSH to my VPS at 192.168.1.100 with key authentication&quot;</span></span>
<span class="line"><span>&quot;Set up WebDAV backup to my NextCloud server&quot;</span></span>
<span class="line"><span>&quot;Enable the device hardware inspection tool&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>The Agent handles the configuration while you just describe what you need.</p><div class="warning custom-block"><p class="custom-block-title">Security Note</p><p>HTTP API, MCP, and WebDAV endpoints are <strong>insecure</strong> unless protected by HTTPS or a trusted network. Always use encrypted connections for production use.</p></div>`,29)])])}const b=a(r,[["render",i]]);export{h as __pageData,b as default};
